<rect x="20" y="78" width="12" height="12" fill="#fb923c"/><text x="38" y="88" fill="#a1a1aa" font-size="13" font-family="sans-serif">Ont réellement acheté (décision)</text>
<line x1="60" y1="360" x2="660" y2="360" stroke="rgba(255,255,255,.15)"/>
